        // const history = useHistory();
        // history.push('/user/profile');
        window.location.href = '/user/profile';
    })
        .catch((value) => {
        message.error('登陆失败：' + value.response.data.message);
    });
};
export const CaptchaCodeTab = ({ form, update, }) => {
    const [code, setCode] = useState({
        ext: '',
        id: '',
        image: '',
    });
    const [lastUpdateTime, setLastUpdateTime] = useState();
    const updateCode = () => {
        captchaCode().then((value) => {
            setCode(value);
            form?.setFieldsValue({ verifyId: value.id });
            setLastUpdateTime(Date.now());
        });
    };
    const autoUpdateCode = () => {
        if (lastUpdateTime && Date.now() - lastUpdateTime < 2000) {
            message.warning('刷新太快啦, 先歇一会').then();
            return;
        }
        updateCode();
    };
    // 监听组件初次渲染时，自动刷新验证码
    useEffect(() => {
        autoUpdateCode();
    }, []);
    // 监听 `update` 变化，触发验证码刷新
    useEffect(() => {
        autoUpdateCode();
    }, [update]);
    // 设置1分钟后自动更新
    useEffect(() => {
        const interval = setInterval(() => {
            if (lastUpdateTime && Date.now() - lastUpdateTime >= 60000) {
                autoUpdateCode();
            }
        }, 60000);
        return () => clearInterval(interval); // 清除定时器
    }, [lastUpdateTime]);
    return (<div style={{ display: 'flex' }}>
      <img style={{
            width: '25%',
            height: '38px',
            marginRight: '5%',
            borderRadius: '5px',
            marginTop: '2px',
        }} src={code.image} onClick={autoUpdateCode} alt={'点击刷新'}/>
      <ProFormText name="verifyId" hidden={true}>
        {code.id}
      </ProFormText>
      <ProFormText style={{ width: '70%', height: '35px' }} name="verifyValue" fieldProps={{
            size: 'large',
            prefix: <SafetyOutlined />,
        }} placeholder={'输入图形验证码'} rules={[
            {
                required: true,
                message: '验证码是必填项!',
            },
        ]}/>
    </div>);
};
export const LoginTab = () => {
    return (<>
      {/*cubeID*/}
      <ProFormText name="loginID" fieldProps={{
            size: 'large',
            prefix: <UserOutlined />,
        }} placeholder={'CubeId / Email / LoginId'} rules={[
