                    buttons.push(<Button style={{ backgroundColor: '#4ba3f6', fontWeight: 700, color: '#ffc', border: 'none' }} size={'small'} autoInsertSpace={false} onClick={() => {
                            history.replace({ pathname: '/admin/organizers/' + curOrg?.id + '/comp/' + result.id + '/result' });
                        }}>
              录入
            </Button>);
                    const handleEnd = async () => {
