                            content: '您确定要结束该比赛吗？结束后将无法恢复。',
                            okText: '确认结束',
                            cancelText: '取消',
                            onOk: handleEnd, // 点击确认后执行结束操作
                        });
                    };
                    buttons.push(<Button style={{ backgroundColor: '#ff3bac', fontWeight: 700, color: '#ffc', border: 'none' }} size={'small'} onClick={showEnd} autoInsertSpace={false}>
              结束
            </Button>);
                }
                if (adminUser !== null && result.Status === 'Reviewing') {
                    const handleApproval = async () => {
                        apiApprovalComp(result.id).then(() => {
                            // @ts-ignore
                            actionRef.current?.reload();
                            message.success("审批通过");
                        }).catch((e) => {
                            message.error(e);
                        });
                    };
                    const showConfirm = () => {
                        Modal.warning({
                            title: '确认审批',
                            content: '确认要通过' + result.Name + '的比赛申请吗?',
                            okText: '确认',
                            cancelText: '取消',
                            onOk: handleApproval,
                        });
                    };
                    buttons.push(<Button style={{ backgroundColor: '#faad14', fontWeight: 700, color: '#ffc', border: 'none' }} size={'small'} autoInsertSpace={false} onClick={showConfirm}>
              审批
            </Button>);
                }
                if (adminUser !== null) {
                    const showDeleteCompModal = () => {
                        let confirmName = '';
                        Modal.confirm({
                            title: '删除比赛',
                            width: 520,
                            content: (<div>
                  <p style={{ marginBottom: 12, color: '#cf1322' }}>
                    此操作将永久删除该比赛及其全部成绩（含预录入）、站点纪录、报名与赞助关联等数据，且不可恢复。
                  </p>
                  <p style={{ marginBottom: 8 }}>
                    请输入比赛名称「{result.Name}」以确认：
                  </p>
                  <Input placeholder="输入比赛全称" onChange={(e) => {
                                    confirmName = e.target.value;
                                }}/>
                </div>),
                            okText: '确认删除',
                            okButtonProps: { danger: true },
                            cancelText: '取消',
                            onOk: async () => {
                                if (confirmName.trim() !== result.Name.trim()) {
                                    message.error('比赛名称不一致，请重新输入');
                                    return Promise.reject();
                                }
                                try {
                                    await apiAdminDeleteComp(result.id);
                                    // @ts-ignore
                                    actionRef.current?.reload();
                                    message.success('比赛已删除');
                                }
                                catch (e) {
                                    message.error('删除失败: ' + e);
                                    return Promise.reject();
                                }
                            },
                        });
                    };
                    buttons.push(<Button style={{ backgroundColor: '#ff0000', fontWeight: 700, color: '#ffc', border: 'none' }} size={'small'} autoInsertSpace={false} onClick={showDeleteCompModal}>
              删除
            </Button>);
                }
                const spacedButtons = buttons.flatMap((btn, index) => index < buttons.length - 1
