                    : [btn]);
                return <>{spacedButtons}</>;
            },
        },
    ];
    return (<>
      <div style={{ marginBottom: 30 }}>
        {BackButton('返回上层')}
        <Link to={'/admin/organizers/Comps/create'} style={{ marginRight: 20, marginLeft: 20 }}>
          <Button type="default" className="create-comp-btn">
            创建比赛
          </Button>
        </Link>
        {!loading && (<>
            <Select placeholder="选择所在团队名称" style={{ width: 200 }} defaultValue={org?.data.items[0]?.id} // 默认选中第一个组织
         onChange={(value) => {
                const selectedOrg = org?.data.items.find((o) => o.id === value) || null;
                setCurOrg(selectedOrg);
            }}>
              {org?.data.items.map((o) => (<Select.Option key={o.id} value={o.id}>
                  {o.Name}
                </Select.Option>))}
            </Select>
          </>)}
      </div>
      {!loading && (<>
          <ProTable key={curOrg?.id} actionRef={actionRef} title={() => {
                return (<h2>
                  {curOrg?.Name} 举办的比赛 (数量{compsCount})
                </h2>);
            }} size="small" columns={[...CompsTableColumns, ...OptCompsTableColumns]} rowClassName={rowClassNameWithStyleLines} request={async () => {
                // @ts-ignore
                const value = await apiGetComps(curOrg?.id);
                let comps = value.data.items;
