                    return 0;
                });
                for (let i = 0; i < comps.length; i++) {
                    comps[i].Index = i + 1;
                }
                setCompsCount(comps.length);
                return { data: comps, success: true, total: value.data.total };
            }} search={false} pagination={false} options={false} sticky/>
        </>)}
    </>);
};
