import { CubesCn } from '@/components/CubeIcon/cube';
import { CubeIcon } from '@/components/CubeIcon/cube_icon';
import { eventRouteM } from '@/components/Data/cube_result/event_route';
import { ResultsTable } from '@/components/Data/cube_result/result_tables';
import { resultStringPro, resultTimeString, } from '@/components/Data/types/result';
import { PlayerLink } from '@/components/Link/Links';
import { rowClassNameWithStyleLines } from '@/components/Table/table_style';
import { NavTabs } from '@/components/Tabs/nav_tabs';
import { Auth, checkAuth } from '@/pages/Admin/AuthComponents/AuthComponents';
import { apiAddCompResults, apiApprovalCompsPreResult, apiDeleteCompsResult, apiGetAllPlayers, apiGetCompsPreResult, apiGetCompsResults, apiGetCompsResultsWithPlayer, apiGetOrgComp, apiOrganizers, } from '@/services/cubing-pro/auth/organizers';
import { apiEvents } from '@/services/cubing-pro/events/events';
import { isNumber } from '@/utils/types/numbers';
import { useParams } from '@@/exports';
import { CloseCircleOutlined, InfoCircleOutlined } from '@ant-design/icons';
import { ProTable } from '@ant-design/pro-table';
import { Alert, Button, Card, Cascader, Form, Input, Modal, Progress, Select, Space, Table, Tag, Tooltip, message, } from 'antd';
import TextArea from 'antd/es/input/TextArea';
import React, { useEffect, useRef, useState } from 'react';
const { Option } = Select;
const OrganizersResults = () => {
    const { orgId, compId } = useParams();
    const actionRef = useRef();
    const [org, setOrg] = useState(null);
    const [comp, setComp] = useState(null);
    const [events, setEvents] = useState([]);
    const [players, setPlayers] = useState();
    // 单个录入
    const [curPlayer, setCurPlayer] = useState();
    const [curSchedule, setCurSchedule] = useState(null);
    const [curEvent, setCurEvent] = useState(null);
    const [oneResults, setOneResults] = useState([]);
    const [scheduleOpt, setScheduleOpt] = useState();
    const [inputValues, setInputValues] = useState(Array(5));
    const [curRound, setCurRound] = useState();
    // 多录入
    const [multiResults, setMultiResults] = useState([]);
    const [parserResults, setParserResults] = useState([]);
    // 录入审批
    const [preResultSelectedRowKeys, setPreResultSelectedRowKeys] = useState([]);
    const [preResults, setPreResults] = useState([]);
    const user = checkAuth([Auth.AuthOrganizers]);
    if (user === null) {
        return <>无权限</>;
    }
    // eslint-disable-next-line react-hooks/rules-of-hooks
    useEffect(() => {
        apiEvents().then((value) => {
            setEvents(value.data.Events);
        });
        // @ts-ignore
        apiGetOrgComp(orgId, compId).then((value) => {
            setComp(value);
            let data = [];
            for (let i = 0; i < value.data.comp_json.Events.length; i++) {
                const ev = value.data.comp_json.Events[i];
                if (ev.EventID === '' || ev.EventID === undefined) {
                    continue;
                }
                let children = [];
                for (let j = 0; j < ev.Schedule.length; j++) {
                    let s = ev.Schedule[j];
                    children.push({
                        value: s.RoundNum,
                        label: s.Round,
                    });
                }
                let v = {
                    value: ev.EventID,
                    label: (<>
              {CubeIcon(ev.EventID, ev.EventID, {})}
              {CubesCn(ev.EventID)}
            </>),
                    children: children,
                };
                data.push(v);
            }
            // @ts-ignore
            setScheduleOpt(data);
        });
        // @ts-ignore
        apiOrganizers(orgId).then((value) => {
            setOrg(value);
        });
        // @ts-ignore
        apiGetAllPlayers(orgId, compId).then((value) => {
            setPlayers(value.data.items);
        });
    }, []);
    if (!comp || !org) {
        return <>loading</>;
    }
    if (comp.data.OrganizersID !== org.data.id) {
        return <>无权限</>;
    }
    const updateRound = (v) => {
        if (v === undefined || v === '' || v === null) {
            return;
        }
        setCurRound(v);
        const ev = comp.data.comp_json.Events.find((value) => {
            return value.EventID === v[0];
        });
        if (ev === undefined) {
            return;
        }
        setCurEvent(ev);
        const schedule = ev.Schedule.find((value) => {
            return value.RoundNum === v[1];
        });
        if (schedule) {
            setCurSchedule(schedule);
        }
        // @ts-ignore
        apiGetCompsResults(orgId, compId, ev.EventID, schedule.RoundNum).then((value) => {
            if (value === undefined || value.data === undefined) {
                return;
            }
            for (let i = 0; i < value.data.length; i++) {
                value.data[i].Rank -= 1;
            }
            setOneResults(value.data);
        });
    };
    const filterOption = (input, option) => {
        const searchText = input.toLowerCase();
        const optionText = option?.label?.toString().toLowerCase() || option?.children?.toString().toLowerCase() || '';
        return optionText.includes(searchText);
    };
    const getEventRoundNum = () => {
        if (!curEvent) {
            return 0;
        }
        const event = events.find((value) => {
            return value.id === curEvent?.EventID;
        });
        if (event === undefined) {
            return 0;
        }
        switch (event.base_route_typ) {
            case 1:
                return 1;
            case 2:
            case 3:
            case 4:
                return 3;
            case 5:
            case 6:
            case 7:
                return 5;
            case 8:
                return 1;
            case 9:
                return 2;
            case 10:
                return 3;
        }
        return 0;
    };
    const filedStyle = {
        width: 300,
    };
    const updateResultValue = (index, value) => {
        const updatedValues = [...inputValues];
        updatedValues[index] = value;
        setInputValues(updatedValues);
    };
    const parseTimeToSeconds = (time) => {
        if (time === 'DNF' || time === 'd' || time === 'D') {
            return -10000;
        }
        if (time === 'DNS') {
            return -10001;
        }
        // 解析纯秒数格式
        if (/^\d+(\.\d+)?$/.test(time)) {
            return parseFloat(time);
        }
        // 解析分+秒格式
        if (/^\d{1,2}[:：]\d{2}(\.\d+)?$/.test(time)) {
            const [minutes, seconds] = time.split(/[:：]/);
            return parseFloat(minutes) * 60 + parseFloat(seconds);
        }
        // 解析时+分+秒格式
        if (/^\d{1,2}[:：]\d{2}[:：]\d{3}(\.\d+)?$/.test(time)) {
            const [hours, minutes, seconds] = time.split(/[:：]/);
            return parseFloat(hours) * 3600 + parseFloat(minutes) * 60 + parseFloat(seconds);
        }
        return -10000;
    };
    // 更新输出框的成绩，不符合的需要删除或更新
    const inputOneResultUpdate = (v, index) => {
        const value = v
            // .replace(/\s+/g, '')
            .replace(/：/g, ':') // 替换所有大写的"："为":"
            .replace(/。/g, '.'); // 替换所有大写的"。"为"."
        updateResultValue(index, value);
        // 确认是否是指定的格式
        if (!curEvent) {
            message.warning('请先选择项目', 2).then();
            return;
        }
        const reg0 = /^\d+\/\d+$/;
        const reg1 = /^(\d+(\.\d*)?)$/;
        const reg2 = /^(\d*[:|：]\d*\.{0,1}\d{0,3})$/;
        const reg3 = /^(\d*[:|：]\d*[:|：]\d*)$/;
        const event = events.find((value) => {
            return value.id === curEvent?.EventID;
        });
        if (!event) {
            message.warning('请先选择一个项目', 2).then();
            return;
        }
        if ([8, 9, 10].indexOf(event.base_route_typ) !== -1) {
            // 多轮项目
            if (value.indexOf(' ') !== -1) {
                const data = value.split(' ');
                const key1 = data[0];
                const key2 = data[1];
                if (!(reg0.test(key1) || reg1.test(key2) || reg2.test(key2) || reg3.test(key2))) {
                    message.warning(value + '不符合多盲格式', 2).then();
                }
                const sl = key1.split('/');
                if (sl.length >= 2) {
                    const num1 = Number(sl[0]);
                    const num2 = Number(sl[1]);
                    if (num2 < num1) {
                        message.warning(value + '录入复原成绩个数不应大于尝试个数', 2).then();
                    }
                }
                return;
            }
            return;
        }
        if (value === 'DNF' || value === 'DNS' || value === 'd' || value === 'D') {
            return;
        }
        // 确认是否符合时间格式
        // 时分秒 {number} : {number} : {number} . {number}
        // 分秒   {number} : {number} . {number}
        // 秒    {number} . {number}
        if (reg1.test(value) || reg2.test(value) || reg3.test(value)) {
            return;
        }
        message.warning(value + '不符合格式', 2).then();
    };
    const checkResult = (input) => {
        const reg = /^((([0-1]?\d|2[0-3]):([0-5]?\d|60):([0-5]?\d|60)(\.\d{1,3})?)|(([0-5]?\d|60):([0-5]?\d|60)(\.\d{1,3})?)|([0-5]?\d(\.\d{1,3})?))$/;
        if (isNumber(input)) {
            return true;
        }
        if (input === 'DNF' || input === 'DNS' || input === 'D' || input === 'd') {
            return true;
        }
        return reg.test(input);
    };
    const onOneFinish = () => {
        if (!curPlayer) {
            message.warning('请选择一个玩家').then();
            return;
        }
        if (!curSchedule) {
            message.warning('请选择一个轮次').then();
            return;
        }
        const event = events.find((value) => {
            return value.id === curEvent?.EventID;
        });
        if (!event) {
            message.warning('请选择一个项目').then();
            return;
        }
        let results = [];
        const reg = /^\d+\/\d+$/;
        for (let i = 0; i < getEventRoundNum(); i++) {
            if (inputValues[i] === null || inputValues[i] === '' || inputValues[i] === undefined) {
                message.warning(`第${i + 1}个成绩未输入`).then();
                return;
            }
            if ([8, 9, 10].indexOf(event.base_route_typ) !== -1) {
                const sl = inputValues[i].split(' ');
                if (sl.length < 2 || !reg.test(sl[0]) || !checkResult(sl[1])) {
                    message.warning(`第${i + 1}个成绩格式不正确, 请按 a/b xx:yy:zz的格式录入`).then();
                    return;
                }
                results.push(Number(sl[0].split('/')[0]), Number(sl[0].split('/')[1]), parseTimeToSeconds(sl[1]));
                continue;
            }
            if (!checkResult(inputValues[i])) {
                message.warning(`第${i + 1}个成绩格式不正确`).then();
                return;
            }
            results.push(parseTimeToSeconds(inputValues[i]));
        }
        apiAddCompResults(orgId, compId, curEvent?.EventID, curSchedule?.RoundNum, results, curPlayer)
            .then(() => {
            message.success('成绩录入成功').then();
            updateRound(curRound);
            setInputValues([]);
        })
            .catch((value) => {
            message.error('成绩录入失败:' + value.response.data.error).then();
        });
    };
    const updateMultiPlayer = (v) => {
        if (v === undefined || v === '' || v === null) {
            setMultiResults([]);
            return;
        }
        apiGetCompsResultsWithPlayer(orgId, compId, v).then((value) => {
            if (value === undefined || value.data === undefined) {
                return;
            }
            setMultiResults(value.data);
        });
        setCurPlayer(v);
    };
    const updateMultiInput = (v) => {
        let slice = v.replaceAll('【', '[').replaceAll('】', ']').split('\n');
        slice = slice.filter((value) => {
            return value !== '';
        });
        let parserResults = [];
        for (let i = 0; i < slice.length; i++) {
            let line = slice[i]
                .replaceAll(',', ' ')
                .replaceAll('，', ' ')
                .replaceAll('(', '')
                .replaceAll(')', '')
                .replaceAll(' [', '[');
            const data = line.split(' ').filter((value) => {
                return value !== '';
            });
            if (data.length <= 1) {
                message.warning(`${slice[i]} 存在格式错误`).then();
                continue;
            }
            let oneLineStr = data[0];
            let result = {
                Index: i + 1,
                EventID: data[0],
                Round: 1,
                RoundNum: 1,
                Result: [],
                Error: '',
                EventRoute: 7,
            };
            if (oneLineStr.indexOf('[') !== -1) {
                const match = oneLineStr.match(/^([a-zA-Z0-9]+)\[(\d+)]$/);
                if (match) {
                    result.EventID = match[1]; // 前面的数字
                    result.Round = Number(match[2]); // 方括号内的数字
                    result.RoundNum = Number(match[2]);
                }
            }
            const evs = events.find((value) => {
                if (result.EventID === '' || result.EventID === undefined) {
                    return false;
                }
                if (value.id === result.EventID ||
                    value.name === result.EventID ||
                    value.cn === result.EventID) {
                    return true;
                }
                // 兼容中文名
                const otherNames = value.otherNames.split(';');
                for (let i = 0; i < otherNames.length; i++) {
                    if (result.EventID === otherNames[i]) {
                        return true;
                    }
                }
                return false;
            });
            if (evs === undefined) {
                result.Error = '项目不存在';
                parserResults.push(result);
                continue;
            }
            result.EventRoute = evs.base_route_typ;
            result.EventID = evs.id;
            if ([8, 9, 10].indexOf(evs.base_route_typ) !== -1) {
                if (data.length < 2) {
                    result.Error = '成绩格式错误';
                }
                const reg = /^\d+\/\d+$/;
                if (!reg.test(data[1]) || !checkResult(data[2])) {
                    result.Error = '成绩格式不正确';
                }
                const sl = data[1].split(' ');
                result.Result.push(
                // @ts-ignore
                Number(sl[0].split('/')[0]), Number(sl[0].split('/')[1]), parseTimeToSeconds(data[2]));
            }
            else {
                for (let j = 1; j < data.length; j++) {
                    if (!checkResult(data[j])) {
                        result.Error = `${data[j]}成绩格式不正确`;
                        break;
                    }
                    // @ts-ignore
                    result.Result.push(parseTimeToSeconds(data[j]));
                }
            }
            console.log(result);
            // 获取项目轮次
            const compEv = comp.data.comp_json.Events.find((value) => {
                return value.EventID === evs.id;
            });
            if (compEv === undefined) {
                result.Error = '本次比赛未开放该项目';
                parserResults.push(result);
                continue;
            }
            // todo 轮次
            const schedule = compEv.Schedule.find((value) => {
                return value.RoundNum === result.Round;
            });
            if (schedule === undefined) {
                result.Error = '本次比赛未开放该轮次';
            }
            else {
                // @ts-ignore
                result.Round = schedule.Round;
            }
            parserResults.push(result);
        }
        setParserResults(parserResults);
    };
    const onMultiFinish = async () => {
        if (parserResults === undefined || parserResults.length === 0) {
            message.error('无成绩可提交').then();
            return;
        }
        if (!curPlayer) {
            message.error('请选择一个玩家').then();
            return;
        }
        for (let i = 0; i < parserResults.length; i++) {
            if (parserResults[i].Error) {
                message.error(`第${i + 1}个成绩存在: ${parserResults[i].Error}错误,请删除后再添加`).then();
                return;
            }
        }
        for (let i = 0; i < parserResults.length; i++) {
            const result = parserResults[i];
            await apiAddCompResults(orgId, compId, result.EventID, result.RoundNum, result.Result, curPlayer)
                .then(() => {
                message.success(result.EventID + ' ' + result.Round + '成绩录入成功');
                updateRound(curRound);
                setInputValues([]);
            })
                .catch((value) => {
                message.error('成绩录入失败:' + value.response.data.error);
            });
        }
        setParserResults([]);
        updateMultiPlayer(curPlayer);
    };
    const deleteResultsColumn = {
        title: '操作',
        dataIndex: 'PersonName',
        key: 'PersonName',
        width: 100,
        render: (value, result) => {
            const showConfirm = () => {
                Modal.warning({
                    title: '是否删除成绩?',
                    content: (<p>
              确认要执行对{result.PersonName}的{result.EventID}-{result.Round}成绩进行删除
            </p>),
                    okText: '删除',
                    okButtonProps: {
                        style: { backgroundColor: 'red', borderColor: 'red', color: 'white' }, // 自定义样式
                    },
                    async onOk() {
                        await apiDeleteCompsResult(orgId, compId, result.id)
                            .then(() => {
                            message.info('成绩删除成功').then();
                        })
                            .catch((value) => {
                            message.error('成绩删除失败:' + value.response.data.error).then();
                        });
                        updateMultiPlayer(curPlayer);
                        updateRound(curRound);
                    },
                });
            };
            return (<Button size={'small'} danger onClick={showConfirm}>
          删除
        </Button>);
        },
    };
    const onInputResult = () => {
        return (<>
        <Form onFinish={onOneFinish} labelCol={{ span: 4 }} wrapperCol={{ span: 14 }}>
          <Card>
            <Form.Item label="选择轮次">
              <Cascader style={filedStyle} options={scheduleOpt} onChange={updateRound} placeholder="选择项目和轮次"/>
            </Form.Item>
            <Form.Item label="选择选手">
              <Select style={filedStyle} placeholder={'输入姓名或 CubeID 筛选已报名选手'} onChange={(value) => {
                setCurPlayer(value);
            }} filterOption={filterOption} clearIcon={<CloseCircleOutlined style={{ color: 'red' }}/>} showSearch allowClear>
                {players?.map((player) => (<Option key={player.CubeID} value={player.CubeID}>
                    {player.CubeID} - {player.Name}
                  </Option>))}
              </Select>
            </Form.Item>

            <Form.Item label={<span>
                  <Tooltip title={<>
                        <p>成绩格式为: xx:yy:zz.www</p>
                        <p>可以输入DNF、DNS、D等代表成绩无效</p>
                        <p>多盲等以 a/b xx:yy:zz 格式录入</p>
                      </>}>
                    <InfoCircleOutlined style={{ marginRight: 5, color: '#d5ad62' }}/>
                  </Tooltip>
                  录入成绩
                </span>}>
              <Space direction="vertical" size={7} style={filedStyle}>
                {Array.from({ length: getEventRoundNum() }, (_, index) => (<Input key={`result${index + 1}`} name={`result${index + 1}`} addonBefore={`${index + 1}`} value={inputValues[index]} placeholder="请输入成绩" onChange={(e) => inputOneResultUpdate(e.target.value, index)}/>))}
              </Space>
            </Form.Item>

            <Form.Item wrapperCol={{ offset: 4, span: 16 }}>
              <Button htmlType="submit">提交</Button>
            </Form.Item>
          </Card>
        </Form>

        {/*成绩列表*/}
        {curEvent && (<Card style={{ marginTop: 20 }}>
            <h1>
              {CubesCn(curEvent?.EventID)} {curSchedule?.Round}
            </h1>
            {ResultsTable(oneResults, ['Rank', 'CubeID', 'PersonName', 'Best', 'Average', 'Result'], undefined, [deleteResultsColumn])}
          </Card>)}
      </>);
    };
    const multiInputResult = () => {
        return (<>
        <Form onFinish={onMultiFinish} labelCol={{ span: 4 }} wrapperCol={{ span: 18 }}>
          <Card>
            <Form.Item label="选择选手">
              <Select style={filedStyle} clearIcon={<CloseCircleOutlined style={{ color: 'red' }}/>} placeholder={'输入姓名或 CubeID 筛选已报名选手'} onChange={(value) => {
                updateMultiPlayer(value);
            }} filterOption={filterOption} showSearch allowClear>
                {players?.map((player) => (<Option key={player.CubeID} value={player.CubeID}>
                    {player.CubeID} - {player.Name}
                  </Option>))}
              </Select>
            </Form.Item>
            <Form.Item label={<span>
                  <Tooltip title={<>
                        <p>录入: 333 1 2 3 4 5</p>
                        <p>允许多个成绩同时录入: 333 1 2 3 4 5 444 1 2 3 4 5, 以换行分割</p>
                        <p>允许DNF, DNS: 333 DNS DNF d s D</p>
                        <p>录入某个轮次的: 333[1] 1 2 3 4 5</p>
                        <p>注意, 请不要输入中文字符</p>
                      </>}>
                    <InfoCircleOutlined style={{ marginRight: 5, color: '#d5ad62' }}/>
                  </Tooltip>
                  批量录入
                </span>}>
              <TextArea style={{ minHeight: 200 }} onChange={(e) => {
                updateMultiInput(e.target.value);
            }}></TextArea>
            </Form.Item>

            <Form.Item label="项目" style={{ width: '100%' }}>
              <Table dataSource={parserResults} 
        // @ts-ignore
        columns={[
                {
                    title: '序号',
                    dataIndex: 'Index',
                    key: 'Index',
                    width: 50,
                },
                {
                    title: '项目',
                    dataIndex: 'EventID',
                    key: 'EventID',
                    width: 100,
                    render: (value) => {
                        return (<>
                          {CubeIcon(value, value, {})} {CubesCn(value)}
                        </>);
                    },
                },
                {
                    title: '轮次',
                    dataIndex: 'Round',
                    key: 'Round',
                    width: 100,
                },
                {
                    title: '成绩',
                    dataIndex: 'Result',
                    key: 'Result',
                    render: (results, result) => {
                        let body = [];
                        // eslint-disable-next-line array-callback-return
                        const data = resultStringPro(results, result.EventRoute);
                        // eslint-disable-next-line array-callback-return
                        data.map((value) => {
                            body.push(<td style={{ minWidth: '80px' }}>{value}</td>);
                        });
                        return (<>
                          {result.Error && <Alert message={result.Error} type="error" showIcon/>}
                          <div className={'cube_result_results_col'}>{body}</div>
                        </>);
                    },
                },
            ]} pagination={false} size="small" scroll={{ x: 'max-content' }} // 启用横向滚动
        />
            </Form.Item>

            <Form.Item wrapperCol={{ offset: 4, span: 16 }} style={{ marginTop: 20 }}>
              <Button htmlType="submit">提交</Button>
            </Form.Item>
          </Card>
        </Form>
        {multiResults && (<Card style={{ marginTop: 20 }}>
            <h2>{curPlayer} 本场比赛成绩</h2>
            {ResultsTable(multiResults, ['EventName', 'Round', 'Best', 'Average', 'Result'], undefined, [deleteResultsColumn])}
          </Card>)}
      </>);
    };
    const onPreResultSelectChange = (newSelectedRowKeys) => {
        setPreResultSelectedRowKeys(newSelectedRowKeys);
    };
    const updatePreResult = async (params) => {
        const value = await apiGetCompsPreResult(orgId, compId, false, params.current ? params.current : 1, params.pageSize ? params.pageSize : 20);
        for (let i = 0; i < value.data.items.length; i++) {
            value.data.items[i].key = value.data.items[i].id;
        }
        setPreResults(value.data.items);
        setPreResultSelectedRowKeys([]);
        return {
            data: value.data.items,
            success: true,
            total: value.data.total,
        };
    };
    const preResultRowSelection = {
        // @ts-ignore
        preResultSelectedRowKeys,
        onChange: onPreResultSelectChange,
        selections: [Table.SELECTION_ALL, Table.SELECTION_INVERT, Table.SELECTION_NONE],
    };
    const onPreResultFinish = (ok) => {
        return () => {
            if (preResultSelectedRowKeys.length === 0) {
                message.warning('你未选择任何成绩').then();
                return;
            }
            const color = ok ? '#a0d911' : 'red';
            let progress = 0;
            let startSend = false;
            Modal.confirm({
                title: ok ? '是否通过' : '是否驳回',
                content: (<>
            <p>{`确认要执行对 ${preResultSelectedRowKeys.length} 个成绩的${ok ? '通过' : '驳回'}操作?`}</p>
            {startSend && (<Progress percent={progress} status={progress === 100 ? 'success' : 'active'}/>)}
          </>),
                okText: ok ? '通过' : '驳回',
                okButtonProps: {
                    style: { backgroundColor: color, borderColor: color, color: 'white' }, // 自定义样式
                },
                async onOk() {
                    startSend = true;
                    for (let i = 0; i < preResultSelectedRowKeys.length; i++) {
                        const k = preResultSelectedRowKeys[i];
                        const res = preResults.find((value) => value.key === k);
                        progress = (i * 100) / preResultSelectedRowKeys.length;
                        if (res === undefined) {
                            continue;
                        }
                        await apiApprovalCompsPreResult(orgId, compId, ok, res.id).catch((error) => {
                            message
                                .error(`保存审批失败: ${res.EventID} - ${res.Round} / ${error.response.data.error}`)
                                .then();
                        });
                    }
                    // @ts-ignore
                    actionRef.current.reload();
                },
            });
        };
    };
    const preResultInputResult = () => {
        return (<>
        <Card>
          <ProTable title={() => {
                return (<>
                  <p style={{ display: 'inline', fontWeight: 700, fontSize: 20 }}>录入审批</p>
                  <Button danger onClick={onPreResultFinish(false)} style={{ float: 'right', marginLeft: 20 }}>
                    驳回
                  </Button>
                  <Button type="primary" color="#a0d911" onClick={onPreResultFinish(true)} style={{ float: 'right' }}>
                    通过
                  </Button>
                </>);
            }} 
        // dataSource={preResults}
        request={updatePreResult} rowSelection={preResultRowSelection} size="small" columns={[
                {
                    title: '项目',
                    dataIndex: 'EventID',
                    key: 'EventID',
                    width: 80,
                    // @ts-ignore
                    render: (value, result) => {
                        return (<td style={{ minWidth: '80px', width: '80px' }}>
                      {CubeIcon(result.EventID, result.EventID, {})} {CubesCn(value)}
                    </td>);
                    },
                },
                {
                    title: '轮次',
                    dataIndex: 'Round',
                    key: 'Round',
                    width: 80,
                },
                {
                    title: '玩家名',
                    dataIndex: 'PersonName',
                    key: 'PersonName',
                    width: 100,
                    // @ts-ignore
                    render: (value, result) => {
                        return <>{PlayerLink(result.CubeID, value, '')}</>;
                    },
                },
                {
                    title: 'CubeID',
                    dataIndex: 'CubeID',
                    key: 'CubeID',
                    width: 120,
                },
                {
                    title: '单次',
                    dataIndex: 'Best',
                    key: 'Best',
                    width: 100,
                    // @ts-ignore
                    render: (results, result) => {
                        const m = eventRouteM(result.EventRoute);
                        let inter = m.integer ? m.integer : false;
                        if (m.repeatedly) {
                            return (<td className={'cube_result_Best_col'}>{resultTimeString(results, true)}</td>);
                        }
                        return (<td className={'cube_result_Best_col'}>{resultTimeString(results, inter)}</td>);
                    },
                },
                {
                    title: '平均',
                    dataIndex: 'Average',
                    key: 'Average',
                    width: 100,
                    // @ts-ignore
                    render: (results, result) => {
                        const m = eventRouteM(result.EventRoute);
                        if (m.repeatedly) {
                            return <td className={'cube_result_Average_col'}>-</td>;
                        }
                        // todo 需要pb
                        return (<td className={'cube_result_Average_col'}>
                      {resultTimeString(results, false, false, m.integer)}
                    </td>);
                    },
                },
                {
                    title: '成绩',
                    dataIndex: 'Result',
                    key: 'Result',
                    // @ts-ignore
                    render: (results, result) => {
                        let body = [];
                        const data = resultStringPro(results, result.EventRoute);
                        // eslint-disable-next-line array-callback-return
                        data.map((value) => {
                            body.push(<td style={{ minWidth: '80px' }}>{value}</td>);
                        });
                        return <div className={'cube_result_results_col'}>{body}</div>;
                    },
                },
                {
                    title: '来源',
                    dataIndex: 'Source',
                    key: 'Source',
                    width: 120,
                },
                {
                    title: '状态',
                    dataIndex: 'Finish',
                    key: 'Finish',
                    width: 100,
                    // @ts-ignore
                    render: (f) => {
                        if (f) {
                            return <Tag color="#52c41a">已审批</Tag>;
                        }
                        return <Tag color="#F4D95B">待审批</Tag>;
                    },
                },
            ]} onReset={() => {
                setPreResultSelectedRowKeys([]);
            }} rowClassName={rowClassNameWithStyleLines} search={false} pagination={{
                showQuickJumper: true,
            }} options={false} actionRef={actionRef} sticky/>
          {/*<ProTable<Comp, CompsAPI.CompsReq>*/}
          {/**/}
          {/*/>*/}
        </Card>
      </>);
    };
    const items = [
        {
            key: 'one',
            label: '录入',
            children: onInputResult(),
        },
        {
            key: 'multi',
            label: '批量录入',
            children: multiInputResult(),
        },
        {
            key: 'pre_result',
            label: '录入审批',
            children: preResultInputResult(),
        },
    ];
    return (<>
      <h2>
        <center>{comp.data.Name} 成绩录入</center>
      </h2>

