            <Form.Item label={<span>
                  <Tooltip title={<>
                        <p>成绩格式为: xx:yy:zz.www</p>
                        <p>可以输入DNF、DNS、D等代表成绩无效</p>
                        <p>多盲等以 a/b xx:yy:zz 格式录入</p>
                      </>}>
                    <InfoCircleOutlined style={{ marginRight: 5, color: '#d5ad62' }}/>
                  </Tooltip>
                  录入成绩
                </span>}>
              <Space direction="vertical" size={7} style={filedStyle}>
                {Array.from({ length: getEventRoundNum() }, (_, index) => (<Input key={`result${index + 1}`} name={`result${index + 1}`} addonBefore={`${index + 1}`} value={inputValues[index]} placeholder="请输入成绩" onChange={(e) => inputOneResultUpdate(e.target.value, index)}/>))}
              </Space>
            </Form.Item>

            <Form.Item wrapperCol={{ offset: 4, span: 16 }}>
              <Button htmlType="submit">提交</Button>
            </Form.Item>
          </Card>
        </Form>

        {/*成绩列表*/}
        {curEvent && (<Card style={{ marginTop: 20 }}>
            <h1>
              {CubesCn(curEvent?.EventID)} {curSchedule?.Round}
            </h1>
            {ResultsTable(oneResults, ['Rank', 'CubeID', 'PersonName', 'Best', 'Average', 'Result'], undefined, [deleteResultsColumn])}
          </Card>)}
      </>);
    };
    const multiInputResult = () => {
        return (<>
        <Form onFinish={onMultiFinish} labelCol={{ span: 4 }} wrapperCol={{ span: 18 }}>
