            <Form.Item label="选择选手">
              <Select style={filedStyle} clearIcon={<CloseCircleOutlined style={{ color: 'red' }}/>} placeholder={'输入姓名或 CubeID 筛选已报名选手'} onChange={(value) => {
                updateMultiPlayer(value);
            }} filterOption={filterOption} showSearch allowClear>
                {players?.map((player) => (<Option key={player.CubeID} value={player.CubeID}>
                    {player.CubeID} - {player.Name}
                  </Option>))}
              </Select>
            </Form.Item>
            <Form.Item label={<span>
                  <Tooltip title={<>
                        <p>录入: 333 1 2 3 4 5</p>
                        <p>允许多个成绩同时录入: 333 1 2 3 4 5 444 1 2 3 4 5, 以换行分割</p>
                        <p>允许DNF, DNS: 333 DNS DNF d s D</p>
                        <p>录入某个轮次的: 333[1] 1 2 3 4 5</p>
                        <p>注意, 请不要输入中文字符</p>
                      </>}>
                    <InfoCircleOutlined style={{ marginRight: 5, color: '#d5ad62' }}/>
                  </Tooltip>
                  批量录入
                </span>}>
              <TextArea style={{ minHeight: 200 }} onChange={(e) => {
                updateMultiInput(e.target.value);
            }}></TextArea>
            </Form.Item>

            <Form.Item label="项目" style={{ width: '100%' }}>
              <Table dataSource={parserResults} 
        // @ts-ignore
        columns={[
                {
                    title: '序号',
                    dataIndex: 'Index',
                    key: 'Index',
                    width: 50,
                },
                {
                    title: '项目',
                    dataIndex: 'EventID',
                    key: 'EventID',
                    width: 100,
                    render: (value) => {
                        return (<>
                          {CubeIcon(value, value, {})} {CubesCn(value)}
                        </>);
                    },
                },
                {
                    title: '轮次',
                    dataIndex: 'Round',
                    key: 'Round',
                    width: 100,
                },
                {
                    title: '成绩',
                    dataIndex: 'Result',
                    key: 'Result',
                    render: (results, result) => {
                        let body = [];
                        // eslint-disable-next-line array-callback-return
                        const data = resultStringPro(results, result.EventRoute);
                        // eslint-disable-next-line array-callback-return
                        data.map((value) => {
                            body.push(<td style={{ minWidth: '80px' }}>{value}</td>);
                        });
                        return (<>
                          {result.Error && <Alert message={result.Error} type="error" showIcon/>}
                          <div className={'cube_result_results_col'}>{body}</div>
                        </>);
                    },
                },
            ]} pagination={false} size="small" scroll={{ x: 'max-content' }} // 启用横向滚动
        />
            </Form.Item>

            <Form.Item wrapperCol={{ offset: 4, span: 16 }} style={{ marginTop: 20 }}>
              <Button htmlType="submit">提交</Button>
            </Form.Item>
          </Card>
        </Form>
        {multiResults && (<Card style={{ marginTop: 20 }}>
            <h2>{curPlayer} 本场比赛成绩</h2>
            {ResultsTable(multiResults, ['EventName', 'Round', 'Best', 'Average', 'Result'], undefined, [deleteResultsColumn])}
          </Card>)}
      </>);
    };
    const onPreResultSelectChange = (newSelectedRowKeys) => {
        setPreResultSelectedRowKeys(newSelectedRowKeys);
    };
    const updatePreResult = async (params) => {
        const value = await apiGetCompsPreResult(orgId, compId, false, params.current ? params.current : 1, params.pageSize ? params.pageSize : 20);
        for (let i = 0; i < value.data.items.length; i++) {
            value.data.items[i].key = value.data.items[i].id;
        }
        setPreResults(value.data.items);
        setPreResultSelectedRowKeys([]);
        return {
            data: value.data.items,
            success: true,
            total: value.data.total,
        };
    };
    const preResultRowSelection = {
        // @ts-ignore
        preResultSelectedRowKeys,
        onChange: onPreResultSelectChange,
        selections: [Table.SELECTION_ALL, Table.SELECTION_INVERT, Table.SELECTION_NONE],
    };
    const onPreResultFinish = (ok) => {
        return () => {
            if (preResultSelectedRowKeys.length === 0) {
                message.warning('你未选择任何成绩').then();
                return;
            }
            const color = ok ? '#a0d911' : 'red';
            let progress = 0;
            let startSend = false;
            Modal.confirm({
                title: ok ? '是否通过' : '是否驳回',
                content: (<>
            <p>{`确认要执行对 ${preResultSelectedRowKeys.length} 个成绩的${ok ? '通过' : '驳回'}操作?`}</p>
            {startSend && (<Progress percent={progress} status={progress === 100 ? 'success' : 'active'}/>)}
          </>),
                okText: ok ? '通过' : '驳回',
                okButtonProps: {
                    style: { backgroundColor: color, borderColor: color, color: 'white' }, // 自定义样式
                },
                async onOk() {
                    startSend = true;
                    for (let i = 0; i < preResultSelectedRowKeys.length; i++) {
                        const k = preResultSelectedRowKeys[i];
                        const res = preResults.find((value) => value.key === k);
                        progress = (i * 100) / preResultSelectedRowKeys.length;
                        if (res === undefined) {
                            continue;
                        }
                        await apiApprovalCompsPreResult(orgId, compId, ok, res.id).catch((error) => {
                            message
                                .error(`保存审批失败: ${res.EventID} - ${res.Round} / ${error.response.data.error}`)
                                .then();
                        });
                    }
                    // @ts-ignore
                    actionRef.current.reload();
                },
            });
        };
    };
    const preResultInputResult = () => {
        return (<>
        <Card>
          <ProTable title={() => {
                return (<>
                  <p style={{ display: 'inline', fontWeight: 700, fontSize: 20 }}>录入审批</p>
                  <Button danger onClick={onPreResultFinish(false)} style={{ float: 'right', marginLeft: 20 }}>
                    驳回
                  </Button>
                  <Button type="primary" color="#a0d911" onClick={onPreResultFinish(true)} style={{ float: 'right' }}>
                    通过
                  </Button>
                </>);
            }} 
        // dataSource={preResults}
        request={updatePreResult} rowSelection={preResultRowSelection} size="small" columns={[
                {
                    title: '项目',
                    dataIndex: 'EventID',
                    key: 'EventID',
                    width: 80,
                    // @ts-ignore
                    render: (value, result) => {
                        return (<td style={{ minWidth: '80px', width: '80px' }}>
                      {CubeIcon(result.EventID, result.EventID, {})} {CubesCn(value)}
                    </td>);
                    },
                },
                {
                    title: '轮次',
                    dataIndex: 'Round',
                    key: 'Round',
                    width: 80,
                },
                {
                    title: '玩家名',
                    dataIndex: 'PersonName',
                    key: 'PersonName',
                    width: 100,
                    // @ts-ignore
                    render: (value, result) => {
                        return <>{PlayerLink(result.CubeID, value, '')}</>;
                    },
                },
                {
                    title: 'CubeID',
                    dataIndex: 'CubeID',
                    key: 'CubeID',
                    width: 120,
                },
                {
                    title: '单次',
                    dataIndex: 'Best',
                    key: 'Best',
                    width: 100,
                    // @ts-ignore
                    render: (results, result) => {
                        const m = eventRouteM(result.EventRoute);
                        let inter = m.integer ? m.integer : false;
                        if (m.repeatedly) {
                            return (<td className={'cube_result_Best_col'}>{resultTimeString(results, true)}</td>);
                        }
                        return (<td className={'cube_result_Best_col'}>{resultTimeString(results, inter)}</td>);
                    },
                },
                {
                    title: '平均',
                    dataIndex: 'Average',
                    key: 'Average',
                    width: 100,
                    // @ts-ignore
                    render: (results, result) => {
                        const m = eventRouteM(result.EventRoute);
                        if (m.repeatedly) {
                            return <td className={'cube_result_Average_col'}>-</td>;
                        }
                        // todo 需要pb
                        return (<td className={'cube_result_Average_col'}>
                      {resultTimeString(results, false, false, m.integer)}
                    </td>);
                    },
                },
                {
                    title: '成绩',
                    dataIndex: 'Result',
                    key: 'Result',
                    // @ts-ignore
                    render: (results, result) => {
                        let body = [];
                        const data = resultStringPro(results, result.EventRoute);
                        // eslint-disable-next-line array-callback-return
                        data.map((value) => {
                            body.push(<td style={{ minWidth: '80px' }}>{value}</td>);
                        });
                        return <div className={'cube_result_results_col'}>{body}</div>;
                    },
                },
                {
                    title: '来源',
                    dataIndex: 'Source',
                    key: 'Source',
                    width: 120,
                },
                {
                    title: '状态',
                    dataIndex: 'Finish',
                    key: 'Finish',
                    width: 100,
                    // @ts-ignore
                    render: (f) => {
                        if (f) {
                            return <Tag color="#52c41a">已审批</Tag>;
                        }
                        return <Tag color="#F4D95B">待审批</Tag>;
                    },
                },
            ]} onReset={() => {
                setPreResultSelectedRowKeys([]);
            }} rowClassName={rowClassNameWithStyleLines} search={false} pagination={{
                showQuickJumper: true,
            }} options={false} actionRef={actionRef} sticky/>
          {/*<ProTable<Comp, CompsAPI.CompsReq>*/}
          {/**/}
          {/*/>*/}
        </Card>
      </>);
    };
    const items = [
        {
            key: 'one',
            label: '录入',
            children: onInputResult(),
        },
        {
            key: 'multi',
            label: '批量录入',
            children: multiInputResult(),
        },
        {
            key: 'pre_result',
            label: '录入审批',
            children: preResultInputResult(),
        },
    ];
    return (<>
      <h2>
        <center>{comp.data.Name} 成绩录入</center>
      </h2>

      <NavTabs type="line" items={items} tabsKey="input_tabs" indicator={{ size: (origin) => origin - 20, align: 'center' }}/>
    </>);
};
export default OrganizersResults;
