                    }}>
              修改
            </Button>
          </>);
            },
        },
    ];
    return (<>
      <div style={{ textAlign: 'right', marginBottom: 16 }}>
        <Button type={'primary'} onClick={() => setNewModalOpen(true)}>
          添加
        </Button>
      </div>
      <Table dataSource={keys} columns={columns} rowKey="id" pagination={{ pageSize: 10 }} size={'small'}/>
      <UpdatePersonModal open={updateModalOpen} onClose={() => {
            fetchDiyRankingKey();
            setUpdateModalOpen(false);
        }} 
    // @ts-ignore
    kv={currentKey}/>

      <CreateRankingModal open={newModalOpen} onCancel={() => {
            setNewModalOpen(false);
        }} onOk={fetchDiyRankingKey}/>
    </>);
};
export default DiyRankingManager;
