import { Auth, checkAuth } from '@/pages/Admin/AuthComponents/AuthComponents';
import ThanksSection from '@/pages/Welcome/ThanksSection';
import { getAcknowledgmentsWithAdmin, setAcknowledgmentsWithAdmin, } from '@/services/cubing-pro/auth/system';
import { PageContainer } from '@ant-design/pro-components';
import { Button, Card, Form, Input, InputNumber, Modal, Space, Table, message, } from 'antd';
import { EyeOutlined, PlusOutlined } from '@ant-design/icons';
import React, { useCallback, useEffect, useState } from 'react';
const emptyThank = () => ({
    wcaID: '',
    nickname: '',
    amount: 0,
    avatar: '',
    other: '',
});
const AdminAcknowledgments = () => {
    const user = checkAuth([Auth.AuthAdmin, Auth.AuthSuperAdmin]);
    const [list, setList] = useState([]);
    const [loading, setLoading] = useState(true);
    const [sortByAmount, setSortByAmount] = useState(null);
    const [editModalOpen, setEditModalOpen] = useState(false);
    const [editingItem, setEditingItem] = useState(null);
    const [editIndex, setEditIndex] = useState(-1);
    const [previewOpen, setPreviewOpen] = useState(false);
    const [form] = Form.useForm();
    const fetchList = useCallback(async () => {
        setLoading(true);
        try {
            const data = await getAcknowledgmentsWithAdmin();
            setList(data ?? []);
        }
        catch (err) {
            message.error('获取赞助列表失败');
            setList([]);
        }
        finally {
            setLoading(false);
        }
    }, []);
    useEffect(() => {
        fetchList();
    }, [fetchList]);
    const displayList = React.useMemo(() => {
        if (sortByAmount === null)
            return list;
        return [...list].sort((a, b) => b.amount - a.amount); // 从大到小
    }, [list, sortByAmount]);
    if (user === null) {
        return <>无权限</>;
    }
    const handleApplySort = async () => {
        if (sortByAmount === null)
            return;
        try {
            await setAcknowledgmentsWithAdmin(displayList);
            message.success('排序已应用');
            setSortByAmount(null);
            fetchList();
        }
        catch {
            message.error('应用排序失败');
        }
    };
    const handleAdd = () => {
        setEditingItem(emptyThank());
        setEditIndex(-1);
        form.setFieldsValue({ nickname: '', amount: 0, wcaID: '', avatar: '', other: '' });
        setEditModalOpen(true);
    };
    const handleEdit = (record, index) => {
        setEditingItem({ ...record });
        setEditIndex(index);
        form.setFieldsValue({
            nickname: record.nickname,
            amount: record.amount,
            wcaID: record.wcaID ?? '',
            avatar: record.avatar ?? '',
            other: record.other ?? '',
        });
        setEditModalOpen(true);
    };
    const handleDelete = async (index) => {
