            await setAcknowledgmentsWithAdmin(newList);
            message.success('删除成功');
            fetchList();
        }
        catch {
            message.error('删除失败');
        }
    };
    const handleSave = async () => {
        try {
            const values = await form.validateFields();
            const item = {
                nickname: values.nickname,
                amount: Number(values.amount),
