            <Input placeholder="头像图片链接"/>
          </Form.Item>
          <Form.Item name="other" label="备注（可选）">
            <Input.TextArea placeholder="其他备注信息" rows={2}/>
          </Form.Item>
        </Form>
      </Modal>

      <Modal title="预览展示效果" open={previewOpen} onCancel={() => setPreviewOpen(false)} footer={null} width={800}>
        {displayList.length > 0 ? (<ThanksSection data={displayList}/>) : (<div style={{ padding: 24, textAlign: 'center', color: '#999' }}>暂无赞助数据</div>)}
      </Modal>
    </PageContainer>);
};
export default AdminAcknowledgments;
