import { useIntl } from '@@/plugin-locale';
import { Auth, checkAuth } from '@/pages/Admin/AuthComponents/AuthComponents';
import ExternalLinkCard from '@/pages/ExternalLinks/ExternalLinkCard';
import ExternalLinksGroupedView, { EXTERNAL_LINKS_LIST_DESC_MAX, } from '@/pages/ExternalLinks/ExternalLinksGroupedView';
import { ExternalLinkIconField } from '@/pages/ExternalLinks/externalLinkIconField';
import '@/pages/ExternalLinks/ExternalLinks.less';
import { findGroupForLinkKey, groupDropId, groupSortId, MAX_TOP_LINKS, moveLinkBetweenGroups, newEmptyLink, parseGroupDropId, parseGroupSortId, pruneOrphanLinks, removeGroup, renameGroup, reorderGroupsOrder, reorderKeysInGroup, toggleTop, } from '@/pages/ExternalLinks/utils';
import { getOtherLinksWithAdmin, setOtherLinksWithAdmin, } from '@/services/cubing-pro/auth/system';
import { emptyOtherLinks } from '@/services/cubing-pro/otherLinksNormalize';
import { PageContainer } from '@ant-design/pro-components';
import { DndContext, KeyboardSensor, PointerSensor, closestCenter, useDroppable, useSensor, useSensors, } from '@dnd-kit/core';
import { SortableContext, rectSortingStrategy, sortableKeyboardCoordinates, useSortable, verticalListSortingStrategy, } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { PlusOutlined } from '@ant-design/icons';
import { Button, Card, Form, Input, Modal, Segmented, Select, Space, message } from 'antd';
