        if (!moveKey || !moveTargetGroup)
            return;
        const key = moveKey;
        const fg = findGroupForLinkKey(data, key);
        if (!fg || fg === moveTargetGroup) {
            setMoveModalOpen(false);
            return;
        }
        setData((d) => moveLinkBetweenGroups(d, key, fg, moveTargetGroup, key));
        setMoveModalOpen(false);
        message.success('已移动');
    };
