        setSaving(true);
        try {
            const cleaned = pruneOrphanLinks(data);
            setData(cleaned);
            await setOtherLinksWithAdmin(cleaned);
            message.success('已保存');
            fetchData();
        }
        catch {
            message.error('保存失败');
        }
        finally {
            setSaving(false);
        }
    };
    if (user === null) {
        return <>无权限</>;
    }
    const groupSortItems = data.groups.map(groupSortId);
    const pinCount = data.tops.length;
    return (<PageContainer title={intl.formatMessage({ id: 'menu.ExternalLinks.adminTitle' })} loading={loading}>
      <Space style={{ marginBottom: 16 }} wrap>
        <Segmented options={[
            { label: '编辑', value: 'edit' },
            { label: '展示', value: 'preview' },
        ]} value={viewMode} onChange={(v) => setViewMode(v)}/>
