                      <span>{g}</span>
                      <Button type="link" size="small" onClick={() => {
                            setRenameTarget(g);
                            setRenameValue(g);
                            setRenameModalOpen(true);
                        }}>
                        重命名
                      </Button>
                      <Button type="link" size="small" danger onClick={() => {
                            if (data.groups.length <= 1) {
                                message.warning('至少保留一个分组');
                                return;
                            }
                            setDeleteGroupName(g);
                            setDeleteGroupOpen(true);
                        }}>
                        删除
                      </Button>
                    </Space>} extra={<Button type="primary" size="small" onClick={() => openAddLink(g)}>
                      添加链接
                    </Button>} styles={{ body: { padding: 16 } }}>
                  <SortableContext id={`links-${g}`} items={keys} strategy={rectSortingStrategy}>
                    <div className="external-links-page">
                      <GroupDropZone groupName={g}>
                        <div className="external-links-grid external-links-grid--max4">
                          {keys.map((key) => {
                        const link = linkByKey.get(key);
                        if (!link)
                            return null;
                        const pinned = data.tops.includes(key);
                        return (<SortableLinkWrap key={key} id={key} link={link} admin={{
                                pinned,
                                pinDisabled: pinCount >= MAX_TOP_LINKS,
                                onPinChange: (v) => {
                                    setData((d) => {
                                        if (v &&
                                            d.tops.length >= MAX_TOP_LINKS &&
                                            !d.tops.includes(key)) {
                                            message.warning(`首页置顶最多 ${MAX_TOP_LINKS} 个`);
                                            return d;
                                        }
                                        return { ...d, tops: toggleTop(d.tops, key, v) };
                                    });
                                },
                                onEdit: () => openEditLink(g, key),
                                onDelete: () => deleteLink(g, key),
                                onMove: () => openMove(key),
                            }}/>);
                    })}
                        </div>
                        {keys.length === 0 && (<div style={{ color: 'var(--ant-color-text-tertiary)', fontSize: 13 }}>
                            该分组暂无链接（可拖入其他分组的卡片）
                          </div>)}
                      </GroupDropZone>
                    </div>
                  </SortableContext>
                </Card>
              </SortableGroupRow>);
            })}
        </SortableContext>
      </DndContext>
        </>)}

      <Modal title={editingKey ? '编辑链接' : '添加链接'} open={linkModalOpen} onOk={submitLink} onCancel={() => setLinkModalOpen(false)} destroyOnClose width={580}>
        <Form form={form} layout="vertical">
          <Form.Item name="name" label="名称" rules={[{ required: true, message: '请输入名称' }]}>
            <Input placeholder="显示名称"/>
          </Form.Item>
          <Form.Item name="desc" label="描述">
            <Input.TextArea rows={3} placeholder="简短说明"/>
          </Form.Item>
          <Form.Item name="url" label="链接 URL" rules={[{ required: true, message: '请输入 URL' }]}>
            <Input placeholder="https://..."/>
          </Form.Item>
          <Form.Item name="icon_url" label="图标 URL（可选）">
            <Input placeholder="https://.../icon.png（优先于下方 icon）"/>
          </Form.Item>
          <Form.Item name="icon" label="图标（图标库或路径）">
            <ExternalLinkIconField iconUrl={iconUrlWatch}/>
          </Form.Item>
        </Form>
      </Modal>

      <Modal title="添加分组" open={groupModalOpen} onOk={addGroup} onCancel={() => setGroupModalOpen(false)}>
        <Input placeholder="分组名称" value={newGroupName} onChange={(e) => setNewGroupName(e.target.value)} onPressEnter={addGroup}/>
      </Modal>

      <Modal title="重命名分组" open={renameModalOpen} onOk={confirmRename} onCancel={() => setRenameModalOpen(false)}>
        <Input value={renameValue} onChange={(e) => setRenameValue(e.target.value)} onPressEnter={confirmRename}/>
      </Modal>

      <Modal title="移动到分组" open={moveModalOpen} onOk={applyMove} onCancel={() => setMoveModalOpen(false)}>
        <Select style={{ width: '100%' }} value={moveTargetGroup} onChange={setMoveTargetGroup} options={data.groups
            .filter((g) => moveKey && findGroupForLinkKey(data, moveKey) !== g)
            .map((x) => ({ label: x, value: x }))}/>
      </Modal>

      <Modal title={`删除分组「${deleteGroupName}」`} open={deleteGroupOpen} onCancel={() => setDeleteGroupOpen(false)} footer={<Space wrap>
            <Button onClick={() => setDeleteGroupOpen(false)}>取消</Button>
            <Button onClick={() => {
                setData((d) => removeGroup(d, deleteGroupName, false));
                setDeleteGroupOpen(false);
                message.success('已删除分组，链接已合并到第一个分组');
            }}>
              仅删分组（链接保留）
            </Button>
            <Button type="primary" danger onClick={() => {
                setData((d) => removeGroup(d, deleteGroupName, true));
                setDeleteGroupOpen(false);
                message.success('已删除分组及链接');
            }}>
              删除分组与链接
            </Button>
          </Space>}>
        <p>「仅删分组」将把该分组内链接移动到列表中的第一个分组；「删除分组与链接」将移除这些链接。</p>
      </Modal>
    </PageContainer>);
};
