import { AdminUserSearchSelect } from '@/components/Admin/AdminUserSearchSelect';
import { apiCreateSportResult, apiDeleteSportResult, apiGetSportEvents, apiGetSportResults, } from '@/services/cubing-pro/sports/sports';
import { ProTable } from '@ant-design/pro-components';
import { Button, DatePicker, Form, Input, Modal, Popconfirm, Select, message } from 'antd';
import dayjs from 'dayjs';
import React, { useEffect, useRef, useState } from 'react';
function parseTimeToSeconds(inputTime) {
    const input = inputTime.trim();
    const parts = input.split(':');
    // 支持：ss.SSS
    if (parts.length === 1) {
        return parseFloat(parts[0]);
    }
    // 支持：mm:ss.SSS、hh:mm:ss.SSS
    let seconds = 0;
    const reversed = parts.reverse();
    if (reversed[0])
        seconds += parseFloat(reversed[0]); // 秒（含毫秒）
    if (reversed[1])
        seconds += parseInt(reversed[1]) * 60; // 分
    if (reversed[2])
        seconds += parseInt(reversed[2]) * 3600; // 时
    return seconds;
}
const formatSecondsToTime = (s) => {
    const minutes = Math.floor(s / 60);
    const seconds = (s % 60).toFixed(2).padStart(5, '0'); // 保留两位小数
    return `${minutes}:${seconds}`;
};
const SportResultList = () => {
    const actionRef = useRef();
    const [form] = Form.useForm();
    const [modalOpen, setModalOpen] = useState(false);
    const [events, setEvents] = useState([]);
    useEffect(() => {
        apiGetSportEvents().then((res) => {
            setEvents(res.data.events);
        });
    }, []);
    const handleCreate = async () => {
        try {
            const values = await form.validateFields();
            const params = {
                ...values,
                user_id: Number(values.user_id),
                result: parseTimeToSeconds(values.result), // 使用新解析函数
                date: values.date.format('YYYY-MM-DD'),
