        </div>
      </Modal>

      <Modal open={exporting} closable={false} maskClosable={false} footer={null} title={null}>
        <div className="algs-export-progress" style={{ padding: 24, textAlign: 'center', minWidth: 280 }}>
          <Progress type="line" percent={exportProgress} showInfo format={(p) => `${(p ?? 0).toFixed(1)}%`} status="active" strokeColor={{ from: '#108ee9', to: '#87d068' }}/>
          <div style={{ marginTop: 16, fontSize: 14, color: 'var(--ant-color-text-secondary)' }}>
            {intl.formatMessage({ id: 'algs.detail.exporting' })}
          </div>
        </div>
      </Modal>

      <div style={{ marginBottom: 16 }}>
        <AlgsFilterPanel {...filterPanelProps}/>
      </div>

      <Row gutter={[16, 16]} style={{ marginBottom: 16 }}>
        {flatAlgs.length >= 8 && (<Col xs={24} sm={12} md={8} lg={6}>
            <FormulaRandomPickCard key={formulaRandomRefreshKey} cube={dcube} classId={dclassId} flatAlgs={flatAlgs} onOpenRandom={() => {
                setFormulaRandomModalMode('random');
                setFormulaRandomModalOpen(true);
            }} onOpenHistory={() => {
                setFormulaRandomModalMode('history');
                setFormulaRandomModalOpen(true);
            }} onPickFormula={openModal}/>
          </Col>)}
        {flatAlgs.length > 0 && (<Col xs={24} sm={12} md={8} lg={6}>
            <Card size="small" style={{
                borderRadius: 12,
                backgroundColor: 'rgba(0, 185, 204, 0.25)',
                borderColor: 'rgba(0, 185, 204, 0.5)',
                cursor: 'pointer',
            }} bodyStyle={{ padding: 16 }} onClick={() => setFormulaPracticeOpen(true)}>
              <div style={{
                display: 'flex',
                alignItems: 'center',
                gap: 8,
                color: 'var(--ant-color-text)',
            }}>
                <PlayCircleOutlined style={{ color: 'rgba(0, 150, 170, 0.9)', fontSize: 18 }}/>
                <span style={{ fontWeight: 500 }}>
                  {intl.formatMessage({ id: 'algs.formulaPractice.start' })}
                </span>
              </div>
              <div style={{ marginTop: 8, fontSize: 12, color: 'var(--ant-color-text-tertiary)' }}>
                {intl.formatMessage({ id: 'algs.formulaPractice.title' })}
              </div>
            </Card>
          </Col>)}
        {flatAlgs.length > 0 && (<Col xs={24} sm={12} md={8} lg={6}>
            <FormulaProficiencyCard key={unskilledRefreshKey} cube={dcube} classId={dclassId} flatAlgs={flatAlgs} onOpenFormulaPractice={() => setFormulaPracticeOpen(true)} refreshKey={unskilledRefreshKey}/>
          </Col>)}
        {flatAlgs.length > 0 && (<Col xs={24} sm={12} md={8} lg={6}>
            <PracticeHistoryStatsCard key={unskilledRefreshKey} cube={dcube} classId={dclassId} refreshKey={unskilledRefreshKey}/>
          </Col>)}
      </Row>

      <FormulaRandomPickModal open={formulaRandomModalOpen} onClose={() => setFormulaRandomModalOpen(false)} mode={formulaRandomModalMode} cube={dcube} classId={dclassId} flatAlgs={flatAlgs} onPickFormula={openModal} onPickSuccess={() => setFormulaRandomRefreshKey((k) => k + 1)}/>

      <UsageInstructionsModal open={usageInstructionsOpen} onClose={() => setUsageInstructionsOpen(false)}/>

      <FormulaPracticeModal open={formulaPracticeOpen} onClose={() => {
            setFormulaPracticeOpen(false);
            setUnskilledRefreshKey((k) => k + 1);
        }} cube={dcube} classId={dclassId} flatAlgs={flatAlgs}/>

      <Drawer title={intl.formatMessage({ id: 'algs.detail.filterDrawer' })} placement="right" onClose={() => setFilterDrawerOpen(false)} open={filterDrawerOpen} width={320}>
        <AlgsFilterPanel {...filterPanelProps} compact/>
      </Drawer>

      <div ref={contentRef} style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
        {groupedAlgs.map((block) => (<div key={`${block.setName}-${block.groupName}`} data-algs-group-card>
            <Card size="small" title={`${block.setName} - ${block.groupName}`} style={{ marginBottom: 0 }}>
            <Row gutter={[12, 12]}>
              {block.algs.map((item) => {
                const idx = globalIdxCounter++;
                return (<Col key={`${item.setName}-${item.groupName}-${item.alg.name}`} xs={12} sm={8} md={6} lg={6} xl={4} xxl={4}>
                    <AlgsFormulaCard cube={dcube} classId={dclassId} setName={item.setName} groupName={item.groupName} alg={item.alg} setColorIndex={block.setColorIndex} formulaFontSize={formulaFontSize} onClick={() => openModal(idx)}/>
                  </Col>);
            })}
            </Row>
            </Card>
          </div>))}
      </div>

      <AlgsFloatButtons onScrollTop={handleScrollTop} onOpenFilter={() => setFilterDrawerOpen(true)} onOpenUsageInstructions={() => setUsageInstructionsOpen(true)} onOpenFormulaPractice={flatAlgs.length > 0 ? () => setFormulaPracticeOpen(true) : undefined}/>

      {modalState && (<AlgsModal open onClose={() => setModalState(null)} cube={dcube} classId={dclassId} items={modalState.algs} currentIndex={modalState.index} onNavigate={(i) => setModalState((prev) => (prev ? { ...prev, index: i } : null))}/>)}
    </div>);
};
