const SimpleSq1Draw = () => {
    const [num, setNum] = useState(0);
    const [corner, setCorner] = useState(0);
    const [edge, setEdge] = useState(0);
    const [reg, setReg] = useState(0); // 角度
    const [baseReg, setBaseReg] = useState(0);
    const [svgPoints, setSvgPoints] = useState([]);
    const [linePoint, setLinePoint] = useState([]);
    const [cubes, setCubes] = useState([]);
    const [cpsOpt, setCpsOpt] = useState([]);
    const [defaultVal, setDefaultVal] = useState();
    const addEdge = () => {
        if (reg + 30 > 360) {
            message.warning(intl.formatMessage({ id: 'draws.sq1.error1.Available_full' })).then();
            return;
        }
        if (edge >= 8) {
            message.warning(intl.formatMessage({ id: 'draws.sq1.error2.full_edge' })).then();
            return;
        }
        for (let i = 0; i < edgeSvgs.length; i++) {
            svgPoints.push({
                key: 'edge' + num + '_' + i,
                d: edgeSvgs[i],
                baseRotate: reg + 30,
                rotate: baseReg,
                rotatePoint: rotatePoint,
