        if (!cubes || cubes.length === 0) {
            message.warning(intl.formatMessage({ id: 'draws.sq1.error4.not_available_delete' })).then();
            return;
        }
        if (cubes.at(-1) === 'edge') {
            setReg(reg - 30);
            setEdge(edge - 1);
            svgPoints.splice(-2, 2); // 先删除最后2个元素
            setSvgPoints([...svgPoints]); // 传递修改后的完整数组
        }
        else if (cubes.at(-1) === 'corner') {
            setReg(reg - 60);
            setCorner(corner - 1);
            svgPoints.splice(-3, 3); // 先删除最后2个元素
            setSvgPoints([...svgPoints]); // 传递修改后的完整数组
        }
        cubes.splice(-1, 1);
        setCubes([...cubes]);
        setDefaultVal('');
    };
    const resetLineReg = (e) => {
        switch (e) {
            case 30:
                setLinePoint([
                    {
                        key: 'sq1_line',
                        d: lineSvgs,
                    },
                ]);
                return;
            case -30:
                setLinePoint([
                    {
                        key: 'sq1_line',
                        d: lineSvgs,
                        rotatePoint: rotatePoint,
                        rotate: 0,
                        baseRotate: -30,
                    },
                ]);
                return;
            case 0:
                setLinePoint([]);
                return;
        }
    };
    const setDefault = (e) => {
        const v = cspMap.get(e);
        if (!v) {
            return;
        }
        let newSvgPoints = [];
        let curReg = 0;
        let curEdge = 0;
        let curCorner = 0;
        let curCubes = [];
        let curNum = num;
        for (let i = 0; i < v.length; i++) {
            const d = v[i];
            if (d === 'e') {
                for (let i = 0; i < edgeSvgs.length; i++) {
                    newSvgPoints.push({
                        key: 'edge' + curNum + '_' + i,
                        d: edgeSvgs[i],
                        baseRotate: curReg + 30,
                        rotate: baseReg,
                        rotatePoint: rotatePoint,
                    });
                }
                curReg += 30;
                curEdge += 1;
                curCubes.push('edge');
            }
            else {
                for (let i = 0; i < cornerSvgs.length; i++) {
                    newSvgPoints.push({
                        key: 'corner' + curNum + '_' + i,
                        d: cornerSvgs[i],
                        baseRotate: curReg + 90,
                        rotate: baseReg,
                        rotatePoint: rotatePoint,
                    });
                }
                curReg += 60;
                curCorner += 1;
                curCubes.push('corner');
            }
            curNum += 1;
        }
        setReg(curReg);
        setSvgPoints(newSvgPoints);
        setEdge(curEdge);
        setCorner(curCorner);
        setCubes(curCubes);
        setNum(curNum);
        setDefaultVal(e);
    };
    useEffect(() => {
        resetLineReg(30);
        let opt = [];
        opt.push({ value: '', label: `- ${intl.formatMessage({ id: 'draws.sq1.None' })} -` });
        cspMap.forEach((value, key) => {
            opt.push({
                value: key,
                label: key,
            });
        });
        setCpsOpt(opt);
        setDefault('星 Star');
        console.log(svgPoints);
    }, []);
    return (<div>
      <DrawPalette svgPoints={[...linePoint, ...svgPoints]} presetColors={baseMinxColor} storageKey={'sq1Draw'} viewBox={'0 0 75 75'} strokeWidthNum={0.2} buttons={<div>
            <div style={{ textAlign: 'center', width: '50%', marginLeft: '25%' }}>
              <Form.Item label={<FormattedMessage id="draws.sq1.Rotate"/>}>
                <Slider defaultValue={0} step={30} min={0} max={180} onChange={resetBaseReg}/>
              </Form.Item>
            </div>
            <div style={{ textAlign: 'center', marginBottom: 20 }}>
              <Space>
                <Form.Item label={<FormattedMessage id="draws.sq1.Central_axis"/>} style={{ marginBottom: 0 }}>
                  <Select defaultValue={30} onChange={resetLineReg} options={[
                { value: 0, label: <FormattedMessage id="draws.sq1.None"/> },
                { value: 30, label: <FormattedMessage id="draws.sq1.Positive_15"/> },
                { value: -30, label: <FormattedMessage id="draws.sq1.Negative_15"/> },
            ]} style={{ width: 100 }}/>
                </Form.Item>

                <Form.Item label={<FormattedMessage id="draws.sq1.Default"/>} style={{ marginBottom: 0 }}>
                  {/*// @ts-ignore*/}
                  <Select onChange={setDefault} value={defaultVal} options={cpsOpt} defaultValue={'星 Star'} style={{ width: 150 }}/>
                </Form.Item>
              </Space>
            </div>

            {/*按钮*/}
            <div>
              <Button onClick={reset} key={'reset_button'} style={{ marginLeft: 10 }} disabled={!(cubes.length > 0)}>
                <FormattedMessage id="draws.reset"/>
              </Button>
              <Button onClick={removeHandler} key={'removeHandler_button'} style={{ marginLeft: 10 }} disabled={!(cubes.length > 0)}>
                <FormattedMessage id="draws.delete"/>
              </Button>
              <Button onClick={addCorner} key={'addCorner_button'} style={{ marginLeft: 10 }} disabled={!(corner < 6 && reg + 60 <= 360)}>
                <FormattedMessage id="draws.sq1.add_corner"/>
