                <FormattedMessage id="draws.sq1.add_edge"/>
              </Button>
            </div>
          </div>}/>
    </div>);
};
const DoubleSq1Draw = () => {
    const [topReg, setTopReg] = useState(0);
    const [svgPointsTop, setSvgPointsTop] = useState([]);
    const [linePointTop, setLinePointTop] = useState([]);
    const [topCspOption, setTopCspOptions] = useState([]);
    const [downReg, setDownReg] = useState(0);
    const [downDefaultVal, setDownDefaultVal] = useState();
    const [svgPointsDown, setSvgPointsDown] = useState([]);
    const [linePointDown, setLinePointDown] = useState([]);
    const [downCspOption, setDownCspOptions] = useState([]);
    // 输入文字
    const [useFont, setUseFont] = useState();
    const [fontsTop, setFontsTop] = useState([]);
    const [fontsDown, setFontsDown] = useState([]);
    const handleSetFontSwitch = (showFont) => {
        console.log(showFont);
        setUseFont(showFont);
        svgPointsTop.map((v) => {
            if (v.key.includes('fonts_')) {
                v.disShow = !showFont;
            }
            return v;
        });
        setSvgPointsTop(svgPointsTop);
        svgPointsDown.map((v) => {
            if (v.key.includes('fonts_')) {
                v.disShow = !showFont;
            }
            return v;
        });
        setSvgPointsDown(svgPointsDown);
    };
    const handleTopFontChange = (index, value) => {
        const newFonts = [...fontsTop];
        newFonts[index] = value;
        setFontsTop(newFonts);
        svgPointsTop.map((v) => {
            if (!v.key.includes('fonts_')) {
                return v;
            }
            const key = '_' + 'top' + '_' + index + '_disable';
            if (v.key.includes(key)) {
                v.text = value;
            }
            return v;
        });
        setSvgPointsTop(svgPointsTop);
    };
    // 更新 fontsDown 中指定索引的字体
    const handleDownFontChange = (index, value) => {
        const newFonts = [...fontsDown];
        newFonts[index] = value;
        setFontsDown(newFonts);
        svgPointsDown.map((v) => {
            if (!v.key.includes('fonts_')) {
                return v;
            }
            const key = '_' + 'down' + '_' + index + '_disable';
            if (v.key.includes(key)) {
                v.text = value;
            }
            return v;
        });
        setSvgPointsDown(svgPointsDown);
    };
    const setDraws = (e, topDown) => {
        const v = cspMap.get(e);
        if (!v) {
            return;
        }
        let newSvgPoints = [];
        let curEdge = 0, curCorner = 0;
        const timestamp = Date.now();
        const baseReg = topDown === 'top' ? topReg : downReg;
        let translate = undefined;
        if (topDown !== 'top') {
            translate = [0, 75];
        }
        let curReg = 0;
        let fonts = [];
        for (let i = 0; i < v.length; i++) {
            const d = v[i];
            const font = `${i}`.toUpperCase();
            const textSize = 6;
            fonts.push(font);
            const fontKey = 'fonts_' + timestamp + '_' + topDown + '_' + i + '_disable';
            switch (d) {
                case 'e':
                    for (let j = 0; j < edgeSvgs.length; j++) {
                        newSvgPoints.push({
                            key: timestamp + '_edge_' + topDown + '_' + i + '_' + j + '_' + curReg,
                            unColorBindKey: j === 0 ? 'sq1DrawDouble-' + fontKey : undefined,
                            d: edgeSvgs[j],
                            baseRotate: curReg + 30,
                            rotate: baseReg,
                            rotatePoint: rotatePoint,
                            translate: translate,
                        });
                    }
                    newSvgPoints.push({
                        disShow: !useFont,
                        key: fontKey,
