                }
                else {
                    setLinePointDown([]);
                }
                return;
        }
        if (!top) {
            line.key = 'sq1_line_down';
            line.translate = [0, 75];
            setLinePointDown([line]);
            return;
        }
        setLinePointTop([line]);
    };
    const handleUpdateTopOpt = (e) => {
        const result = setDraws(e, 'top');
