            return;
        }
        const [curE, curC] = result;
        let wantE = 8 - curE;
        let wantC = 8 - curC;
        let opt = [];
        cspMap.forEach((value, key) => {
            const eCount = value.split('e').length - 1;
            const cCount = value.split('c').length - 1;
