      <DrawPalette width={300} height={600} svgPoints={[...linePointTop, ...linePointDown, ...svgPointsTop, ...svgPointsDown]} presetColors={baseMinxColor} storageKey={'sq1DrawDouble'} viewBox={'0 0 75 150'} strokeWidthNum={0.2} buttons={<>
            <div style={{ display: 'flex', gap: 16 }}>
              <Form.Item label={<strong>文字</strong>}>
                <Switch onChange={handleSetFontSwitch}/>
              </Form.Item>
            </div>

            {/*顶层*/}
            <div style={{ display: 'flex', gap: 16 }}>
              <Form.Item label={<strong>顶层</strong>} style={{ marginBottom: 0 }}>
                {/* @ts-ignore */}
                <Select onChange={handleUpdateTopOpt} options={topCspOption} defaultValue={'星 Star'} style={{ width: 150 }}/>
              </Form.Item>

              <Form.Item label={'中轴线'} style={{ marginBottom: 0 }}>
                <Select defaultValue={30} onChange={(e) => {
                resetLineReg(e, true);
            }} options={[
                { value: 0, label: <FormattedMessage id="draws.sq1.None"/> },
                { value: 30, label: <FormattedMessage id="draws.sq1.Positive_15"/> },
                { value: -30, label: <FormattedMessage id="draws.sq1.Negative_15"/> },
            ]} style={{ width: 100 }}/>
              </Form.Item>
              <div style={{ textAlign: 'center', width: '50%' }}>
                <Form.Item label={<FormattedMessage id="draws.sq1.Rotate"/>}>
                  <Slider defaultValue={0} step={30} min={0} max={180} onChange={(e) => {
                resetBaseReg(e, 'top');
            }}/>
                </Form.Item>
              </div>
            </div>

            {useFont && fontsTop && fontsTop.length > 0 && (<>
                <Form.Item label={<strong>顶层文字</strong>} style={{ marginBottom: 0 }}>
                  <Row gutter={[8, 8]}>
                    {fontsTop.map((font, index) => (<Col span={8} key={`top-font-${index}`}>
                        <Input value={font} maxLength={1} onChange={(e) => handleTopFontChange(index, e.target.value)} placeholder="Enter Value"/>
                      </Col>))}
                  </Row>
                </Form.Item>
              </>)}

            {/*底层*/}
            <div style={{ display: 'flex', gap: 16, marginTop: 15 }}>
              <Form.Item label={<strong>底层</strong>} style={{ marginBottom: 0 }}>
                {/* @ts-ignore */}
                <Select onChange={handleUpdateDownOpt} options={downCspOption} value={downDefaultVal} style={{ width: 150 }}/>
              </Form.Item>

              <Form.Item label={'中轴线'} style={{ marginBottom: 0 }}>
                <Select defaultValue={-30} onChange={(e) => {
                resetLineReg(e, false);
            }} options={[
                { value: 0, label: <FormattedMessage id="draws.sq1.None"/> },
                { value: 30, label: <FormattedMessage id="draws.sq1.Positive_15"/> },
                { value: -30, label: <FormattedMessage id="draws.sq1.Negative_15"/> },
            ]} style={{ width: 100 }}/>
              </Form.Item>

              <div style={{ textAlign: 'center', width: '50%' }}>
                <Form.Item label={<FormattedMessage id="draws.sq1.Rotate"/>}>
                  <Slider defaultValue={0} step={30} min={0} max={180} onChange={(e) => {
                resetBaseReg(e, 'down');
            }}/>
                </Form.Item>
              </div>
            </div>

            {useFont && fontsDown && fontsDown.length > 0 && (<>
                <Form.Item label={<strong>底层文字</strong>} style={{ marginBottom: 0 }}>
                  <Row gutter={[8, 8]}>
                    {fontsDown.map((font, index) => (<Col span={8} key={`down-font-${index}`}>
                        <Input value={font} maxLength={1} onChange={(e) => handleDownFontChange(index, e.target.value)} placeholder="Enter Value"/>
                      </Col>))}
                  </Row>
                </Form.Item>
              </>)}
          </>}/>
    </div>);
};
const Sq1Draw = () => {
