};
const extractVenue = (venue) => {
    const match = venue.match(/\[(.*?)\]\((.*?)\)/);
    if (match) {
        return { text: match[1], url: match[2] };
    }
    return { text: venue };
};
const isRegistrationNotStarted = (open) => {
    const now = new Date();
    const openDate = new Date(open);
    return now < openDate;
};
const isRegistrationClosed = (close) => {
    const now = new Date();
    const closeDate = new Date(close);
    return now > closeDate;
};
const isRegistrationOpen = (open, close) => {
    const now = new Date();
    const openDate = new Date(open);
    const closeDate = new Date(close);
    return now >= openDate && now <= closeDate;
};
const formatToBeijingTime = (utcString) => {
    return new Date(utcString).toLocaleString('zh-CN', {
        timeZone: 'Asia/Shanghai',
        hour12: false,
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
    });
};
const WcaCompetitionList = () => {
    const [data, setData] = useState({});
    const [loading, setLoading] = useState(false);
    const [progress, setProgress] = useState(0);
    const [allFetched, setAllFetched] = useState(false);
    const fetchSingleCountry = async (key) => {
        if (!data[key]) { // 如果数据不存在，则请求
            try {
                const params = new URLSearchParams({
                    country_iso2: key,
                    include_cancelled: 'false',
                    ongoing_and_future: new Date(Date.now() - 86400000).toISOString().split('T')[0],
                    page: '1',
                });
                const res = await axios.get(`https://www.worldcubeassociation.org/api/v0/competition_index?${params}`);
                setData((prevData) => ({ ...prevData, [key]: res.data || [] }));
            }
            catch (e) {
                setData((prevData) => ({ ...prevData, [key]: [] }));
            }
        }
    };
    const fetchDataForAllCountries = async () => {
        if (!allFetched) { // 如果还没有获取过所有国家的数据，则发起请求
            if (allFetched)
                return; // 已经加载过就不再重复请求
            const countries = Object.keys(COUNTRY_MAP);
            const notLoadedCountries = countries.filter(key => !(key in data));
            if (notLoadedCountries.length === 0)
                return;
            setLoading(true);
            setProgress(0);
            await Promise.all(notLoadedCountries.map(async (key, index) => {
                await fetchSingleCountry(key); // 复用 fetchSingleCountry 的逻辑
                setProgress(Math.round(((index + 1) / notLoadedCountries.length) * 100));
            }));
            setLoading(false);
            setAllFetched(true);
        }
    };
    useEffect(() => {
        fetchSingleCountry('CN');
    }, []);
    const renderItem = (item) => {
        const start = new Date(item.start_date);
        const end = new Date(item.end_date);
        const days = Math.ceil((end.getTime() - start.getTime()) / (1000 * 3600 * 24)) + 1;
        const venueParsed = extractVenue(item.venue);
        let openTag = <Tag color="red">不可报名</Tag>;
        if (isRegistrationNotStarted(item.registration_open)) {
            openTag = <Tag color="orange">未开始报名</Tag>;
        }
        else if (isRegistrationOpen(item.registration_open, item.registration_close)) {
            openTag = <Tag color="green">可报名</Tag>;
        }
        else if (isRegistrationClosed(item.registration_close)) {
            openTag = <Tag color="red">报名已结束</Tag>;
        }
        return (<List.Item>
        <Card title={<a href={`https://www.worldcubeassociation.org/competitions/${item.id}`} target="_blank" rel="noopener noreferrer">
              {item.name}
            </a>}>
          <p>
            <Text strong>城市：</Text>
            {item.city}
          </p>
          <p>
            <Text strong>比赛日期：</Text>
            {item.start_date} 至 {item.end_date} <Tag color="blue">{days} 天</Tag>
          </p>
          <p>
            <Text strong>比赛地点：</Text>
            {venueParsed.url ? (<Link href={venueParsed.url} target="_blank" rel="noopener noreferrer">
                {venueParsed.text}
              </Link>) : (venueParsed.text)}
          </p>
          <p>
            <Text strong>项目列表：</Text>
            {item.event_ids.map((eid) => (<Tag key={eid}>{eid}</Tag>))}
          </p>
          <p>
            <Text strong>
              报名时间(北京时间): {formatToBeijingTime(item.registration_open)} ~{' '}
              {formatToBeijingTime(item.registration_close)}
            </Text>
          </p>
          <p>
            <Text strong>报名状态：</Text>
            {openTag}
          </p>
        </Card>
      </List.Item>);
    };
    const renderList = (comps, key) => {
        return (<List grid={{
                gutter: 16,
                xs: 1,
                sm: 1,
                md: 2, // 中等屏幕及以上为两列
                lg: 3,
                xl: 3,
                xxl: 3,
            }} dataSource={comps} renderItem={renderItem} locale={{
                emptyText: (<div style={{ textAlign: 'center', padding: 32 }}>
              <Empty description="暂无比赛"/>
              <Button type="primary" style={{ marginTop: 16 }} onClick={() => {
                        fetchSingleCountry(key).then(() => {
                            message.success("刷新成功").then();
                        });
                    }}>
                刷新
              </Button>
            </div>),
            }}/>);
    };
    const tabItems = [
        ...Object.entries(COUNTRY_MAP).map(([key, { label, icon }]) => ({
            key,
            label: (<span>
          {icon} {label}
        </span>),
            children: renderList(data[key], key),
        })),
        {
            key: 'ALL',
            label: (<>
          <FlagOutlined /> 全部
        </>),
            children: loading ? (<div style={{ padding: 32, textAlign: 'center' }}>
          <Progress percent={progress} status="active"/>
          <div style={{ marginTop: 8 }}>正在加载比赛数据…</div>
        </div>) : (Object.entries(data).map(([key, comps]) => (<div key={key} style={{ marginBottom: 24 }}>
            <Title level={4}>
              {COUNTRY_MAP[key].icon} {COUNTRY_MAP[key].label}
            </Title>
            {renderList(comps, key)}
          </div>))),
        },
    ];
    return (<Tabs items={tabItems} defaultActiveKey="CN" destroyInactiveTabPane onChange={(activeKey) => {
            if (activeKey === 'ALL') {
                fetchDataForAllCountries().then();
            }
            else {
                fetchSingleCountry(activeKey).then();
            }
        }}/>);
};
export default WcaCompetitionList;
