import WCAPlayerDetails from '@/pages/WCA/PlayerComponents/PlayerDetails';
import WCAPlayerResultTable from '@/pages/WCA/PlayerComponents/PlayerResultTable';
import WCAPlayerStaticsTab from '@/pages/WCA/PlayerComponents/WCAPlayerStaticsTab';
import { GetPlayerRankTimers, getWCAPersonCompetitions, getWCAPersonProfile, getWCAPersonResults, } from '@/services/cubing-pro/wca/player';
import { apiGetWCAPersonProfile } from '@/services/cubing-pro/wca/wca_api';
import { useParams } from '@@/exports';
import { useIntl } from '@@/plugin-locale';
import { Col, Row, Spin } from 'antd';
import React, { useEffect, useState } from 'react';
const notAvatarUrl = 'https://assets.worldcubeassociation.org/assets/062b138/assets/missing_avatar_thumb-d77f478a307a91a9d4a083ad197012a391d5410f6dd26cb0b0e3118a5de71438.png';
const banAvatarKey = ['2016XUWE02'];
const WCAPlayer = () => {
    const { wcaId } = useParams();
    const intl = useIntl();
    const [is404, setIs404] = useState(false);
    const [loading, setLoading] = useState(true);
    const [wcaProfile, setWcaProfile] = useState();
    const [wcaResults, setWcaResults] = useState([]);
    const [comps, setComps] = useState([]);
    const [wcaRankTimer, setWcaRankTimer] = useState([]);
    // ✅ 设置页面标题的 useEffect —— 必须放在 return 之前，且无条件调用
    useEffect(() => {
        if (!loading && wcaProfile?.name) {
            document.title = intl.formatMessage({ id: 'wca.player.pageTitle' }, { name: wcaProfile.name });
        }
    }, [loading, wcaProfile?.name, intl]);
    const fetchPlayer = async () => {
        if (!wcaId) {
            setLoading(false);
            setIs404(true);
            return;
        }
        try {
            const [profileRes, compsRes, resultsRes, rankTimers] = await Promise.all([
                getWCAPersonProfile(wcaId),
                getWCAPersonCompetitions(wcaId),
                getWCAPersonResults(wcaId),
                GetPlayerRankTimers(wcaId),
            ]);
            // 处理 banAvatarKey
            if (banAvatarKey.includes(wcaId)) {
                profileRes.thumb_url = notAvatarUrl;
            }
            // 先设置基础 profile
            setWcaProfile(profileRes);
            setComps(compsRes);
            setWcaResults(resultsRes);
            setWcaRankTimer(rankTimers);
            setIs404(false);
            // ✅ 异步获取更准确的头像 URL（不阻塞主流程）
            apiGetWCAPersonProfile(wcaId)
                .then(res => {
                // 安全更新：基于当前状态创建新对象
                setWcaProfile(prev => {
                    if (!prev)
                        return prev;
                    return {
                        ...prev,
                        thumb_url: res.person.avatar.thumb_url || prev.thumb_url, // fallback to existing
                    };
                });
            })
                .catch(err => {
                console.warn('Failed to fetch updated avatar from WCA API:', err);
                // 可选：保留原头像，或设为默认
            });
        }
        catch (error) {
            console.error('Failed to fetch player data:', error);
            setIs404(true);
            setWcaProfile(undefined);
            setComps([]);
            setWcaResults([]);
        }
        finally {
            setLoading(false);
        }
    };
    useEffect(() => {
        setLoading(true);
        fetchPlayer().then();
    }, [wcaId]);
    // ❌ 所有 return 必须在所有 hooks 之后
    if (is404) {
        return (<div style={{ textAlign: 'center', color: '#999', marginTop: 50 }}>
        {intl.formatMessage({ id: 'wca.player.notFound' })}
      </div>);
    }
    if (loading || !wcaProfile) {
        return (<div style={{ textAlign: 'center', marginTop: 100 }}>
        <Spin size="large" tip={intl.formatMessage({ id: 'wca.player.loading' })}/>
      </div>);
    }
    // ✅ 正常渲染 - 响应式布局：与 1200px 内容区对齐，卡片在列宽内 100% 铺满
    return (<div style={{
            width: '100%',
            maxWidth: 1200,
            margin: '0 auto',
            padding: '0 16px',
            boxSizing: 'border-box',
        }}>
      <Row gutter={[0, 24]}>
        <Col xs={24} sm={24} md={24} lg={24}>
          <WCAPlayerDetails wcaProfile={wcaProfile} wcaResults={wcaResults}/>
        </Col>
        <Col xs={24} sm={24} md={24} lg={24}>
          <WCAPlayerResultTable wcaProfile={wcaProfile} wcaResults={wcaResults}/>
        </Col>
        <Col xs={24} sm={24} md={24} lg={24}>
          <WCAPlayerStaticsTab wcaProfile={wcaProfile} wcaResults={wcaResults} comps={comps} wcaRankTimer={wcaRankTimer}/>
        </Col>
      </Row>
    </div>);
};
export default WCAPlayer;
