import { CompsTableColumns } from '@/components/Data/cube_comps/comps_tables';
import { rowClassNameWithStyleLines } from '@/components/Table/table_style';
import { apiComps } from '@/services/cubing-pro/comps/comps';
import { ProTable } from '@ant-design/pro-table';
import React, { useRef, useState } from 'react';
const Competitions = () => {
    const actionRef = useRef();
    const [tableParams, setTableParams] = useState({
        size: 20,
        page: 1,
        name: '',
    });
    const resetParams = () => {
        setTableParams({
            ...tableParams,
            name: '',
        });
    };
    return (<>
      <ProTable title={() => {
            return <h2>赛事列表</h2>;
        }} size="small" columns={CompsTableColumns} onReset={resetParams} params={tableParams} rowClassName={rowClassNameWithStyleLines} request={async (params) => {
            // @ts-ignore
            const name = params.Name;
            setTableParams({
                ...tableParams,
                name: name,
            });
            const value = await apiComps(tableParams);
            let comps = value.data.items;
            comps = comps.sort((a, b) => {
                if (a.IsDone && !b.IsDone)
                    return 1;
                if (!a.IsDone && b.IsDone)
                    return -1;
                return 0;
            });
            for (let i = 0; i < comps.length; i++) {
                comps[i].Index = (tableParams.page - 1) * tableParams.size + i + 1;
            }
            return { data: comps, success: true, total: value.data.total };
        }} search={{
            labelWidth: 'auto',
            defaultColsNumber: 1,
            defaultCollapsed: false,
            span: { xs: 24, sm: 24, md: 24, lg: 18, xl: 18, xxl: 12 },
        }} pagination={{
            showQuickJumper: true,
            current: tableParams.page,
            pageSize: tableParams.size,
        }} onChange={(pagination) => {
            setTableParams({
                ...tableParams,
                page: pagination.current ? pagination.current : 1,
                size: pagination.pageSize ? pagination.pageSize : 20,
            });
        }} options={false} actionRef={actionRef} sticky/>
    </>);
};
export default Competitions;
